refsection.programlisting:
X = [ones(1000,1) grand(1000,1,'nor',0,1) grand(1000,1,'nor',0,1)];
b = [0;1;-1];
e = grand(1000,1,'nor',0,1);
y = X*b + e;

gmmopt = tlist(['gmm';'momt';'jake';'prt';'gmmit';'S']);
gmmopt('prt')=1;
gmmopt('gmmit') = 1;
gmmopt('S')='W';
gmmopt('momt')='gmmLinM';
gmmopt('jake')='gmmLinJ';

b0=zeros(3,1);

 uout=gmm('y',gmmopt,'exo=''X''','ivar=''X''','parm0=b0');
 R = 'p1';
 rw=gmmNlWald(uout,R);
//Examples taken from gmmLin_d(): Test if the first parameter is null
